using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fixed: Changed from AddSingleton to AddScoped. A singleton capturing a scoped
// service is a captive dependency — .NET 9 enables ValidateScopes in development
// by default and will throw InvalidOperationException at startup.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// Fixed: .NET 9 HttpClientFactory uses SocketsHttpHandler by default.
// The previous cast to HttpClientHandler would throw InvalidCastException.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });
// Fixed: .NET 9 Trace-level HttpClientFactory logs redact all header values by
// default. Allowlist the specific non-sensitive headers you need to see unredacted.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h != "X-Request-Id" && h != "Accept"));
// Fixed: .NET 9 ForwardedHeadersMiddleware now ignores X-Forwarded-* headers from
// proxies not in KnownProxies or KnownNetworks. Add your trusted proxy address(es).
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("10.0.0.1")); // TODO: replace with your actual proxy IP
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

